-- Structured starter context for the subjects currently supported by StudyBridge.
-- The official syllabi are versioned by the exam boards; source URLs below are
-- the authority and this seed is an AI grounding summary, not a verbatim copy.

insert into public.syllabus_sources (id, exam_board, title, source_url, notes)
values
  ('waec-elearning-subjects', 'WAEC', 'WAEC e-Learning subject standards',
   'https://www.waeconline.org.ng/e-learning/',
   'Use the current WAEC subject page as the authority for updates.'),
  ('jamb-ibass-syllabus', 'JAMB', 'JAMB Integrated Brochure and Syllabus System',
   'https://ibass.jamb.gov.ng/',
   'JAMB publishes current subject PDFs through IBASS; verify the active version before an exam cycle.')
on conflict (id) do update set
  title = excluded.title,
  source_url = excluded.source_url,
  notes = excluded.notes,
  retrieved_at = now();

insert into public.syllabus_subjects (id, exam_board, subject_code, subject_name, source_id)
values
  ('waec.mathematics', 'WAEC', 'MAT', 'Mathematics', 'waec-elearning-subjects'),
  ('jamb.mathematics', 'JAMB', 'MAT', 'Mathematics', 'jamb-ibass-syllabus'),
  ('waec.physics', 'WAEC', 'PHY', 'Physics', 'waec-elearning-subjects'),
  ('jamb.physics', 'JAMB', 'PHY', 'Physics', 'jamb-ibass-syllabus'),
  ('waec.chemistry', 'WAEC', 'CHE', 'Chemistry', 'waec-elearning-subjects'),
  ('jamb.chemistry', 'JAMB', 'CHE', 'Chemistry', 'jamb-ibass-syllabus')
on conflict (id) do update set
  subject_name = excluded.subject_name,
  source_id = excluded.source_id,
  is_active = true;

